#version 300 es
precision highp float;

// ===============================================
// v2.27 — White highlight overlay via u_image4.A
//
// NEW: White anime-style outline / highlight overlay that sits on top of
// ALL other output layers (skin, clothing, non-skin — entire body mask).
//
//   u_image4.A  — greyscale line mask (white=overlay, black=transparent)
//   u_int8=1    — enable the overlay (0=off, default)
//   u_float7    — overlay strength (0=none, 1=full, >1 amplifies dim masks)
//
// Applied AFTER all skin/shadow/overlay processing:
//   fc2 (Unity) and fc3 (Unreal) receive the white composite.
//   fc0 (ILM) intentionally clean — lighting data, no art layers.
//   fc1 (SR Preview) inherits automatically from fc2.
//
// When u_int7=1 (mannequin): pack the line mask into the mannequin
// image's alpha channel — both features share u_image4 cleanly.
//
// ─────────────────────────────────────────────────
// v2.26 — Luminance weights upgraded to BT.709 (modern sRGB standard)
//
// CHANGE from v2.25:
//   All three luminance calculations switched from BT.601 (legacy NTSC)
//   to BT.709 (modern sRGB / Rec.709):
//     OLD: dot(rgb, vec3(0.2126, 0.7152, 0.0722))   — BT.601 / NTSC
//     NEW: dot(rgb, vec3(0.2126, 0.7152, 0.0722)) — BT.709 / sRGB
//
//   Matches Unity's internal luma calculations + the BD luma standard now
//   exposed across BrainDead nodes (BD_LuminanceMask, BD_NormalizeLuma,
//   BD_PackChannels, BD_ImageToGreyscale all default to bt709).
//
//   Perceptually accurate for modern displays. Green gets more weight (~72%
//   vs ~59%) because that's actually how human vision works under modern
//   display whites — BT.601's numbers were calibrated for old NTSC SD video.
//
//   Visual result: slightly brighter greens, slightly darker blues/reds.
//   May shift V-curve thresholds a hair — recheck u_float0 (mid_grey) if you
//   tuned it precisely before.
//
// ─────────────────────────────────────────────────
// v2.25 — fc2 IS the MainTex in Unity (corrected interpretation)
//
// Source of truth: Compiled-Shader Graphs-SkinMask.shader + user clarification
// "fc2 replaces our MainTex in unity so it's the new 'clothing, character etc'"
//
// Unity shader does:
//   inner   = Lerp(SkinColor × SkinMask.A, MainTex.RGB, MainTex.A)
//   output  = inner × max(SkinMask.A, MainTex.A)
//   discard if max-alpha < 0.5
//
// Where fc2 = MainTex (we provide), SkinMask defaults to white (Unity material
// default = "white", so SkinMask.A = 1.0 everywhere unless user overrides).
//
// SIMPLIFIED formula when SkinMask.A = 1:
//   inner  = Lerp(SkinColor, fc2.RGB, fc2.A)
//   output = inner × max(1, fc2.A) = inner
//   = SkinColor × (1 - fc2.A) + fc2.RGB × fc2.A   (standard alpha-over)
//
// fc2.alpha V-curve goes back to ORIGINAL direction (midtone=0, extremes=1):
//   - Midtone skin (alpha=0)    → result = SkinColor (pure tint)
//   - Skin shadow ext (alpha=1) → result = fc2.RGB = dark grey
//   - Skin hi ext (alpha=1)     → result = fc2.RGB = light grey (or white via G overlay)
//   - Non-skin (alpha=1)        → result = fc2.RGB = original (clothes/eyes preserved)
//   - Lines (alpha=1)           → result = line_color (true black/white lines)
//   - Highlight overlay (alpha=1, fc2.RGB=white) → result = PURE WHITE possible!
//   - Dark overlay (alpha=1, fc2.RGB=black)      → result = PURE BLACK possible!
//
// CHANGE from v2.20:
//   fc1 now implements the EXACT compiled Unity formula:
//     1. Approximates SkinMask.A as 1.0 (Unity default)
//     2. Computes: Lerp(SkinColor × 1.0, fc2.RGB, fc2.A) × max(1.0, fc2.A)
//     3. Applies discard-at-0.5 (rarely triggers since max-alpha ≥ 1 in body)
//
//   fc2 behavior matches v2.20 exactly (no changes to RGB or alpha logic).
//   The fc1 fix simply makes the preview reflect what Unity actually computes.
//
// NOTE: If user provides a non-default SkinMask in Unity (e.g. skin mask texture),
// the visible result will differ proportionally. Most Unity setups use the
// default white SkinMask, so this preview matches the common case.
//
// ─────────────────────────────────────────────────
// v2.20 — Line alpha convention: white=line (normal mask)
//
// CHANGE from v2.19:
//   u_image3.alpha now follows the normal mask convention used by G and B channels:
//     alpha=1 (white) = LINE pixel
//     alpha=0 (black) = no line
//   Removed the (1.0 - alpha) inversion.
//
//   All three overlay channels (G, B, A) now share the same "black=no change,
//   white=apply effect" semantics. R remains a brightness map (mid=neutral)
//   because it's designed to accept a real 3D shadow render.
//
// ─────────────────────────────────────────────────
// v2.19 — Overlay channels moved to u_image3 RGBA pack
//
// CHANGES from v2.18:
//
//   u_image2 reverted to its v2.17 role (unchanged):
//     u_int12=0 → ignore
//     u_int12=1 → pre-baked greyscale source for V-curve
//
//   u_image3 now packs FOUR things in RGBA channels:
//     R = SHADOW shading map (greyscale — drives shadow_mult, was: full RGB luma)
//     G = HIGHLIGHT overlay (paint white opaque spots)
//     B = DARK overlay (paint black opaque spots)
//     A = LINE mask (alpha=0 = line, unchanged)
//
//   Greyscale shadow maps still work: when R=G=B (greyscale image), shadow_line.r
//   equals luminance. Only behaviour change: shadow now reads R channel instead of
//   computing luminance from RGB. Existing shadow renders are unaffected.
//
//   For colored shadow maps: pre-convert to greyscale before feeding u_image3.
//
//   Overlay strengths:
//     u_float3 = highlight (G) strength (default 1.0)
//     u_float5 = dark (B) strength (default 1.0)
//     u_float7 = [available]
//
//   Each overlay channel contributes to fc2.alpha so the painted modifications
//   show through in Unity's composite.
//
//   Line opacity (u_float6) still wins at line pixels (from v2.18).
// ===============================================

uniform sampler2D u_image0;   // Character image RGB + body mask alpha (A=body mask)
uniform sampler2D u_image1;   // Skin mask (white=skin zones)
uniform sampler2D u_image2;   // Pre-baked greyscale (used when u_int12=1)
uniform sampler2D u_image3;   // RGBA pack: R=shadow, G=highlight, B=dark, A=line (white=line)
uniform sampler2D u_image4;   // Mannequin body (u_int7=1) / White overlay source (u_int8=1, reads .A channel)
//
// u_image4 / u_int7 PARTIAL SWAP — design note
// ─────────────────────────────────────────────
// u_int7=1 switches src_color → mannequin.rgb, which drives the grey/shading
// pipeline (grey_src, mq_grey_shaded, V-curve, shadow, overlay). Effect per output:
//
//   fc0 ILM    — fully mannequin-driven (grey_lum_shaded owns everything)
//   fc2 Unity  — skin zone uses mannequin shading; NON-SKIN still reads original.rgb
//   fc3 Unreal — same partial split as fc2
//   fc1 SR     — inherited from fc2
//   body mask  — ALWAYS original.a (mannequin.a is never used)
//
// Mannequin is designed as a SEPARATE RUN layered over the base image,
// not a full replacement. Run the shader twice — once with original, once with
// mannequin — and composite the results in the workflow.
//
// TODO: add u_int9 "full swap" mode that also routes:
//   bodyMaskRaw = (u_int9>0) ? mannequin.a : original.a
//   fc2_rgb non-skin = src_color  (instead of original.rgb)
//   fc3_rgb non-skin = src_color  (instead of original.rgb)
// NOTE: u_int8 is now used for white highlight overlay (v2.27) — use u_int9 for full swap
// ─────────────────────────────────────────────

uniform float u_float0;   // V-curve midpoint (default 0.48)
uniform float u_float1;   // V-curve power — 0.5=sharp, 1.0=linear (default 0.5)
uniform float u_float2;   // Outer band — distance from mid where alpha=1.0 (default 0.40)
uniform float u_float3;   // Highlight overlay strength — u_image3.G (default 1.0)
uniform float u_float4;   // Body Mask Threshold (default 0.5)
uniform float u_float5;   // Dark overlay strength — u_image3.B (default 1.0)
uniform float u_float6;   // Line Opacity — 0=invisible, 1=fully opaque line (default 1.0)
uniform float u_float7;   // White highlight overlay strength — u_image4.A (default 1.0)
uniform float u_float8;   // Skin Desaturation Amount (default 1.0)
uniform float u_float9;   // [available]
uniform float u_float10;  // [available]
uniform float u_float11;  // [available]
uniform float u_float12;  // [available]
uniform float u_float13;  // [available]
uniform float u_float14;  // [available]
uniform float u_float15;  // RGB Shadow Depth (default 0.70)
uniform float u_float16;  // Shadow Map Strength — applied to u_image3.R (default 0.40)
uniform float u_float17;  // RGB Highlight Push (default 0.80)
uniform float u_float18;  // [available]
uniform float u_float19;  // [available]

uniform int u_int0;       // [available]
uniform int u_int1;       // Line Color: 0=black (default), 1=white
uniform int u_int2;       // Line Mask: 0=off, 1=on (lineMask = u_image3.alpha, white=line)
uniform int u_int3;       // Skin Tint R (0-255, default 255)
uniform int u_int4;       // Skin Tint G (0-255, default 255)
uniform int u_int5;       // Skin Tint B (0-255, default 255)
uniform int u_int6;       // [available]
uniform int u_int7;       // Source: 0=original.rgb, 1=mannequin u_image4
uniform int u_int8;       // White highlight overlay: 0=off, 1=from u_image4.A
uniform int u_int9;       // [available]
uniform int u_int10;      // [available]
uniform int u_int11;      // [available]
uniform int u_int12;      // u_image2 mode: 0=ignore, 1=pre-baked greyscale source

in vec2 v_texCoord;

layout(location = 0) out vec4 fragColor0;  // fc0 — ILM
layout(location = 1) out vec4 fragColor1;  // fc1 — SR Preview / BD Parts 2D (fc2 + tint baked)
layout(location = 2) out vec4 fragColor2;  // fc2 — Unity skin layer (RGB=visual, A=tint mask)
layout(location = 3) out vec4 fragColor3;  // fc3 — Unreal 3D UEFN albedo

void main() {
    vec4 original  = texture(u_image0, v_texCoord);
    vec4 mannequin = texture(u_image4, v_texCoord);
    float skinMask    = texture(u_image1, v_texCoord).r;
    float bodyMaskRaw = original.a;

    // ── White highlight overlay from u_image4.A (u_int8=1) ──────────────────
    float whiteOverlay = (u_int8 > 0)
        ? clamp(mannequin.a * max(u_float7, 0.0), 0.0, 1.0)
        : 0.0;

    // ── u_image3: R=shadow, G=highlight, B=dark, A=line ──
    vec4 img3 = texture(u_image3, v_texCoord);
    float shadowLum = img3.r;  // greyscale shadow (R channel)
    float hi_raw   = img3.g;   // highlight overlay raw value
    float dark_raw = img3.b;   // dark overlay raw value
    float lineMask = (u_int2 > 0) ? img3.a : 0.0;  // white=line (no inversion)

    float bodyMask = step(u_float4, bodyMaskRaw);
    if (bodyMask < 0.01) {
        fragColor0 = vec4(0.0);
        fragColor1 = vec4(0.0);
        fragColor2 = vec4(0.0);
        fragColor3 = vec4(0.0);
        return;
    }

    float shmap_str    = max(u_float16, 0.0);          // no upper clamp — values >1.0 amplify shadow contrast
    float desat_amount = clamp(u_float8,  0.0, 1.0);
    float rgb_hi_push  = clamp(u_float17, 0.0, 1.0);
    float rgb_lo_depth = clamp(u_float15, 0.0, 1.0);
    float line_str     = clamp(u_float6,  0.0, 1.0);

    float mid_grey   = clamp(u_float0, 0.01, 0.99);
    float vcurve_pwr = max(u_float1, 0.01);
    float outer_band = clamp(u_float2, 0.01, 1.0);
    float hi_thresh  = clamp(mid_grey + outer_band * 0.9, 0.01, 0.99);
    float lo_thresh  = clamp(mid_grey - outer_band * 0.9, 0.01, 0.99);

    // Overlay strengths
    float ovr_hi_str   = max(u_float3, 0.0);   // no upper clamp — values >1.0 amplify highlight channel
    float ovr_dark_str = max(u_float5, 0.0);   // no upper clamp — values >1.0 amplify dark channel
    float ovr_hi   = hi_raw   * ovr_hi_str;
    float ovr_dark = dark_raw * ovr_dark_str;

    vec3  line_color = (u_int1 > 0) ? vec3(1.0) : vec3(0.0);

    vec3  src_color = (u_int7 > 0) ? mannequin.rgb : original.rgb;
    float src_lum   = dot(src_color, vec3(0.2126, 0.7152, 0.0722));

    // ── Grey source ──
    vec3 grey_src;
    if (u_int12 == 1) {
        grey_src = texture(u_image2, v_texCoord).rgb;  // pre-baked grey
    } else {
        grey_src = mix(src_color, vec3(src_lum), desat_amount);
    }

    // ── Hi/lo push on grey_src ──
    float grey_lum_raw = dot(grey_src, vec3(0.2126, 0.7152, 0.0722));
    float hi_w = smoothstep(hi_thresh - 0.08, hi_thresh + 0.08, grey_lum_raw);
    grey_src   = mix(grey_src, vec3(1.0), hi_w * rgb_hi_push);
    float lo_w = smoothstep(lo_thresh + 0.08, lo_thresh - 0.08, grey_lum_raw);
    grey_src   = grey_src * mix(1.0, 1.0 - rgb_lo_depth, lo_w);

    // ── Shadow multiply from u_image3.R ──
    float shadow_mult    = mix(1.0, shadowLum * 2.0, shmap_str);
    vec3  mq_grey_shaded = clamp(grey_src * shadow_mult, 0.0, 1.0);

    // ── Apply overlay layers (highlight and dark) ──
    mq_grey_shaded = mix(mq_grey_shaded, vec3(1.0), ovr_hi);    // G: white opaque overlay
    mq_grey_shaded = mix(mq_grey_shaded, vec3(0.0), ovr_dark);  // B: black opaque overlay
    mq_grey_shaded = clamp(mq_grey_shaded, 0.0, 1.0);

    float grey_lum_shaded = dot(mq_grey_shaded, vec3(0.2126, 0.7152, 0.0722));

    // ── V-curve alpha from shaded grey ──
    float dist_from_mid = abs(grey_lum_shaded - mid_grey);
    float t             = clamp(dist_from_mid / outer_band, 0.0, 1.0);
    float vcurve_alpha  = pow(t, vcurve_pwr);

    // ── Shadow alpha kick from u_image3.R ──
    float shadow_strength = abs(shadowLum - 0.5) * 2.0;
    float shadow_alpha    = shadow_strength * shmap_str;

    // ── Overlay alpha kicks ──
    float overlay_alpha = max(ovr_hi, ovr_dark);

    // Combined skin alpha — V-curve OR shadow kick OR overlay kick
    float skin_alpha_combined = max(max(vcurve_alpha, shadow_alpha), overlay_alpha);

    vec3 skin_tint = vec3(
        clamp(float(u_int3), 0.0, 255.0),
        clamp(float(u_int4), 0.0, 255.0),
        clamp(float(u_int5), 0.0, 255.0)
    ) / 255.0;


    // ══════════════════════════════════════════════════════
    // fc0: ILM — lines NOT applied (intentionally clean)
    // ══════════════════════════════════════════════════════
    float ilm_lum = clamp(grey_lum_shaded, 0.0, 1.0);
    fragColor0 = vec4(
        smoothstep(0.72, 0.90, ilm_lum),
        ilm_lum,
        smoothstep(0.15, 0.42, ilm_lum) * (1.0 - smoothstep(0.42, 0.72, ilm_lum)),
        bodyMask
    );


    // ══════════════════════════════════════════════════════
    // fc2: Unity 2D Skin Layer
    // Line opacity (u_float6) ALWAYS controls fc2.alpha at line pixels.
    // ══════════════════════════════════════════════════════
    vec3 fc2_skin_rgb = mix(mq_grey_shaded, line_color, lineMask);
    vec3 fc2_rgb_raw  = mix(original.rgb, fc2_skin_rgb, skinMask);
    fc2_rgb_raw       = mix(fc2_rgb_raw, vec3(1.0), whiteOverlay);  // white highlight on top
    vec3 fc2_rgb      = fc2_rgb_raw * bodyMask;

    float fc2_alpha_skin = mix(1.0, skin_alpha_combined, skinMask);
    float fc2_alpha  = mix(fc2_alpha_skin, line_str, lineMask);
    fc2_alpha        = max(fc2_alpha, whiteOverlay);  // white overlay is fully opaque
    fc2_alpha       *= bodyMask;
    fragColor2 = vec4(clamp(fc2_rgb, 0.0, 1.0), clamp(fc2_alpha, 0.0, 1.0));


    // ══════════════════════════════════════════════════════
    // fc1: SR Preview / BD Parts 2D  (fc2 with skin_tint baked flat)
    // ══════════════════════════════════════════════════════
    // !!! THIS IS IMMUTABLE - NEVER CHANGE UNLESS FABLE STUDIOS INFORMS US!
    // START IMMUTABLE SECTION
    // EXACT compiled Unity formula:
    //   inner  = Lerp(SkinColor × SkinMask.A, fc2.RGB, fc2.A)
    //   output = inner × max(SkinMask.A, fc2.A)
    //   discard if max-alpha < 0.5
    //
    // SkinMask.A is assumed = 1.0 (Unity default "white" texture). To preview a
    // non-default SkinMask, the user can substitute their texture and re-run.
    float skinmask_a = 1.0;
    float fc2_alpha_unclamped = fc2_alpha / max(bodyMask, 0.001);  // undo bodyMask scale
    vec3  fc2_rgb_unclamped   = fc2_rgb  / max(bodyMask, 0.001);

    float max_a = max(skinmask_a, fc2_alpha_unclamped);
    vec3  inner = mix(skin_tint * skinmask_a, fc2_rgb_unclamped, fc2_alpha_unclamped);
    vec3  visible = inner * max_a;

    // Alpha clip at 0.5 (Unity discards below this)
    float kept = step(0.5, max_a);
    vec3  fc1_rgb = visible * kept * bodyMask;
    float fc1_alpha = max_a * kept * bodyMask;
    fragColor1 = vec4(clamp(fc1_rgb, 0.0, 1.0), clamp(fc1_alpha, 0.0, 1.0));
    // !!! THIS IS IMMUTABLE - NEVER CHANGE UNLESS FABLE STUDIOS INFORMS US!
    // END IMMUTABLE SECTION

    // ══════════════════════════════════════════════════════
    // fc3: Unreal 3D UEFN Albedo (clean — ILM carries lighting)
    // ══════════════════════════════════════════════════════
    vec3  fc3_grey    = mix(src_color, vec3(src_lum), desat_amount);
    vec3  fc3_rgb_raw = mix(original.rgb, fc3_grey, skinMask);
    fc3_rgb_raw       = mix(fc3_rgb_raw, vec3(1.0), whiteOverlay);  // white highlight on top
    vec3  fc3_rgb     = fc3_rgb_raw * bodyMask;
    float fc3_alpha   = mix(1.0, skin_alpha_combined, skinMask);
    fc3_alpha         = max(fc3_alpha, whiteOverlay);
    fc3_alpha        *= bodyMask;
    fragColor3 = vec4(clamp(fc3_rgb, 0.0, 1.0), clamp(fc3_alpha, 0.0, 1.0));
}
